
// ── Cursor
const dot=document.getElementById('cur-dot'),ring=document.getElementById('cur-ring');
let mx=0,my=0,rx=0,ry=0;
document.addEventListener('mousemove',e=>{mx=e.clientX;my=e.clientY});
(function a(){rx+=(mx-rx)*.1;ry+=(my-ry)*.1;
  dot.style.cssText=`left:${mx}px;top:${my}px`;
  ring.style.cssText=`left:${rx}px;top:${ry}px`;
  requestAnimationFrame(a)})();
document.querySelectorAll('a,button,.pc,.gi,.feat').forEach(el=>{
  el.addEventListener('mouseenter',()=>document.body.classList.add('link-hover'));
  el.addEventListener('mouseleave',()=>document.body.classList.remove('link-hover'));
});

// ── Scroll progress
const prog=document.getElementById('prog');
window.addEventListener('scroll',()=>{
  const pct=window.scrollY/(document.documentElement.scrollHeight-window.innerHeight)*100;
  prog.style.width=pct+'%';
  document.getElementById('nav').classList.toggle('stuck',scrollY>60);
});

// ── Reveal
const io=new IntersectionObserver(e=>e.forEach(x=>{if(x.isIntersecting)x.target.classList.add('vis')}),{threshold:.1});
document.querySelectorAll('.rv,.rl,.rr').forEach(el=>io.observe(el));

// ── Ticker duplicate
const tk=document.getElementById('tk');tk.innerHTML+=tk.innerHTML;
const mn=document.getElementById('mn');mn.innerHTML+=mn.innerHTML;

// ── Lightbox
const lb=document.getElementById('lb'),lbImg=document.getElementById('lb-img');
const srcs=['data:image/jpeg;base64,','data:image/jpeg;base64,','data:image/jpeg;base64,'];
let cur=0;
document.querySelectorAll('.gi').forEach((el,i)=>{
  el.addEventListener('click',()=>{cur=i;lbImg.src=srcs[i];lb.classList.add('open')});
});
document.getElementById('lb-close').addEventListener('click',()=>lb.classList.remove('open'));
document.getElementById('lb-prev').addEventListener('click',()=>{cur=(cur-1+srcs.length)%srcs.length;lbImg.src=srcs[cur]});
document.getElementById('lb-next').addEventListener('click',()=>{cur=(cur+1)%srcs.length;lbImg.src=srcs[cur]});
lb.addEventListener('click',e=>{if(e.target===lb)lb.classList.remove('open')});
document.addEventListener('keydown',e=>{if(e.key==='Escape')lb.classList.remove('open')});

// ── Parallax hero
window.addEventListener('scroll',()=>{
  const bg=document.querySelector('.hero-bg');
  if(bg) bg.style.transform=`scale(1) translateY(${window.scrollY*.25}px)`;
});

// ── Hamburger menu
const hamBtn=document.getElementById('ham');
const mobMenu=document.getElementById('mob-menu');
function closeMob(){
  hamBtn.classList.remove('open');
  mobMenu.classList.remove('open');
  document.body.style.overflow='';
}
hamBtn.addEventListener('click',()=>{
  const isOpen=mobMenu.classList.toggle('open');
  hamBtn.classList.toggle('open');
  document.body.style.overflow=isOpen?'hidden':'';
});
mobMenu.addEventListener('click',e=>{if(e.target===mobMenu)closeMob()});
document.addEventListener('keydown',e=>{if(e.key==='Escape')closeMob()});

// ── Animate stat numbers
const statObs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{
    if(e.isIntersecting){
      const el=e.target.querySelector('.exp-val');
      if(!el||el.dataset.animated)return;
      el.dataset.animated=1;
      const txt=el.textContent;
      if(/^\d+/.test(txt)){
        const n=parseInt(txt);let i=0;
        const t=setInterval(()=>{i+=Math.ceil(n/30);if(i>=n){i=n;clearInterval(t)}el.textContent=i+(txt.includes('%')? '%':'')},40);
      }
    }
  });
},{threshold:.5});
document.querySelectorAll('.exp-item').forEach(el=>statObs.observe(el));
